// API 接口：提供实时监控数据
const fs = require('fs');
const path = require('path');

// 读取模拟数据
const simulationData = JSON.parse(
  fs.readFileSync(path.join(__dirname, '../../data/simulation_data.json'), 'utf8')
);

// 获取总览统计
exports.getOverview = (req, res) => {
  const stats = simulationData.company_stats;
  res.json({
    success: true,
    data: {
      totalTasks: stats.total_tasks_completed,
      projectsShipped: stats.projects_shipped,
      totalCommits: stats.total_commits,
      reportsGenerated: stats.reports_generated,
      feishuPushes: stats.feishu_pushes,
      avgEfficiency: stats.avg_daily_efficiency
    }
  });
};

// 获取单个 Agent 的详细信息
exports.getAgentStats = (req, res) => {
  const { agentName } = req.params;
  const agent = simulationData.agents[agentName];

  if (!agent) {
    return res.status(404).json({ success: false, error: 'Agent not found' });
  }

  res.json({
    success: true,
    data: agent
  });
};

// 获取所有 Agent 的列表
exports.getAllAgents = (req, res) => {
  const agents = Object.keys(simulationData.agents).map(key => ({
    name: key,
    displayName: simulationData.agents[key].name,
    role: simulationData.agents[key].role,
    totalStats: simulationData.agents[key].total_stats
  }));

  res.json({
    success: true,
    data: agents
  });
};

// 获取三天数据对比
exports.getDailyComparison = (req, res) => {
  const comparison = {};

  Object.keys(simulationData.agents).forEach(agentKey => {
    const agent = simulationData.agents[agentKey];
    comparison[agentKey] = agent.daily_output.map(output => ({
      date: output.date,
      status: output.status,
      timeSpent: output.time_spent
    }));
  });

  res.json({
    success: true,
    data: comparison
  });
};

// 获取项目进度
exports.getProjectProgress = (req, res) => {
  const developer = simulationData.agents.developer;
  const projects = {};

  developer.daily_output.forEach(day => {
    day.projects.forEach(project => {
      if (!projects[project.name]) {
        projects[project.name] = {
          name: project.name,
          history: []
        };
      }
      projects[project.name].history.push({
        date: day.date,
        progress: project.progress,
        status: project.status
      });
    });
  });

  res.json({
    success: true,
    data: Object.values(projects)
  });
};
